// =============================================================================
// Check Your Representative - Interactive State -> County -> City selector
// -----------------------------------------------------------------------------
// Click a state on the map -> get that state's county list -> pick a county ->
// get its city list. Selection fires onSelect callbacks so the profile builder
// (next phase) can attach the right district / bills to a constituent.
//
// DATA:
//   - States geometry + county-name index are EMBEDDED below (simplified, real
//     Census/us-atlas data) so this runs offline. For production, set
//     props.dataSources to your hosted full-resolution files and the component
//     fetches instead of using the embed. Drop these on your site:
//       /public/data/statesGeo.json        (full-res, shipped alongside)
//       /public/data/countiesByState.json  (shipped alongside)
//       GET /api/cities?countyFips=08069 -> { cities: ["Loveland", ...] }
//   - Cities are served by your API. A small real CO sample is embedded only so
//     the city step is demonstrable in preview (see CITIES_SAMPLE).
//
// Internal naming kept per project convention.
// =============================================================================

import React, { useMemo, useRef, useState, useEffect, useCallback } from "react";
import * as d3 from "d3";

const MAP_CSS = `
  @media (max-width: 600px) {
    .cyr-map-header { padding: 12px 14px 4px !important; }
    .cyr-map-header h2 { font-size: 18px !important; }
    .cyr-map-body { padding: 8px 12px 18px !important; gap: 12px !important; }
    .cyr-map-list-item { padding: 10px 12px !important; font-size: 14px !important; }
  }
`;
if (typeof document !== "undefined" && !document.getElementById("cyr-map-css")) {
  const _ms = document.createElement("style");
  _ms.id = "cyr-map-css";
  _ms.textContent = MAP_CSS;
  document.head.appendChild(_ms);
}


const C = {
  crimson:"#8B0000", crimsonBright:"#B22234", navy:"#0A1A3F", navySoft:"#14213D",
  gold:"#C9A227", parchment:"#FBF7EC", parchmentEdge:"#F0E6CE", ink:"#1A1A1A",
  muted:"#5C5347", line:"#D8C9A0", waterEdge:"#BFD3D8",
};
const serif = "Georgia, 'Times New Roman', serif";

export default function ConstituentMap({
  dataSources = null,                 // {statesGeo, countiesByState, citiesEndpoint} to use hosted data
  onStateSelect, onCountySelect, onCitySelect,
}) {
  const [statesGeo, setStatesGeo] = useState(() => dataSources ? null : EMBED_STATES_GEO);
  const [countiesByState, setCountiesByState] = useState(() => dataSources ? null : EMBED_COUNTIES);

  const [selState, setSelState] = useState(null);   // {fips,name,abbr}
  const [selCounty, setSelCounty] = useState(null); // {fips,name}
  const [countyFilter, setCountyFilter] = useState("");
  const [cities, setCities] = useState(null);
  const [citiesLoading, setCitiesLoading] = useState(false);
  const citiesDbRef = useRef(null); // nationwide cities-by-county, loaded once on first use

  // Optional production fetch of hosted data
  useEffect(() => {
    if (!dataSources) return;
    (async () => {
      const [g, c] = await Promise.all([
        fetch(dataSources.statesGeo).then(r => r.json()),
        fetch(dataSources.countiesByState).then(r => r.json()),
      ]);
      setStatesGeo(g); setCountiesByState(c);
    })().catch(() => {/* fall back to embed if you prefer */});
  }, [dataSources]);

  // --- projection + paths ---
  const W = 720, H = 460;
  const pathGen = useMemo(() => {
    if (!statesGeo) return null;
    const proj = d3.geoAlbersUsa().fitSize([W, H], statesGeo);
    return d3.geoPath(proj);
  }, [statesGeo]);

  const selectState = useCallback((feat) => {
    const s = { fips: feat.id, name: feat.properties.name, abbr: feat.properties.abbr };
    setSelState(s); setSelCounty(null); setCities(null); setCountyFilter("");
    onStateSelect && onStateSelect(s);
  }, [onStateSelect]);

  const selectCounty = useCallback(async (county) => {
    setSelCounty(county); setCities(null);
    onCountySelect && onCountySelect({ ...county, state: selState });
    setCitiesLoading(true);
    try {
      let list;
      if (dataSources?.citiesEndpoint) {
        const r = await fetch(`${dataSources.citiesEndpoint}?countyFips=${county.fips}`);
        list = (await r.json()).cities || [];
      } else {
        // Lazy-load the nationwide cities-by-county file on first use, then cache it.
        if (!citiesDbRef.current) {
          const url = `${import.meta.env.BASE_URL}data/citiesByCounty.json`;
          citiesDbRef.current = await fetch(url).then(r => r.json());
        }
        list = citiesDbRef.current[county.fips] || [];
      }
      setCities(list);
    } catch { setCities([]); }
    finally { setCitiesLoading(false); }
  }, [dataSources, selState, onCountySelect]);

  const counties = (selState && countiesByState?.[selState.fips]) || [];
  const filtered = countyFilter
    ? counties.filter(c => c.name.toLowerCase().includes(countyFilter.toLowerCase()))
    : counties;

  return (
    <div style={{ fontFamily: serif, color: C.ink, background: C.parchment,
                  border:`1px solid ${C.line}`, borderRadius:6, overflow:"hidden", maxWidth: 1040, margin:"0 auto" }}>
      <StarStrip />
      <div className="cyr-map-header" style={{ padding:"16px 20px 6px" }}>
        <div style={{ textTransform:"uppercase", letterSpacing:2, fontSize:11, color:C.gold, fontWeight:700 }}>
          Find Your Jurisdiction
        </div>
        <h2 style={{ margin:"3px 0 0", fontSize:22, color:C.navy }}>
          {selState ? selState.name : "Select your state"}
          {selCounty && <span style={{ color:C.crimson }}> · {selCounty.name} County</span>}
        </h2>
      </div>

      <div className="cyr-map-body" style={{ display:"flex", flexWrap:"wrap", gap:16, padding:"8px 20px 22px" }}>
        {/* MAP */}
        <div style={{ flex:"1 1 460px", minWidth:320 }}>
          {!pathGen
            ? <div style={{ padding:40, textAlign:"center", color:C.muted }}>Loading map…</div>
            : <svg viewBox={`0 0 ${W} ${H}`} style={{ width:"100%", height:"auto", background:"#fff",
                     border:`1px solid ${C.line}`, borderRadius:4 }}>
                <g>
                  {statesGeo.features.map(f => {
                    const active = selState?.fips === f.id;
                    return (
                      <path key={f.id} d={pathGen(f)}
                        onClick={() => selectState(f)}
                        style={{ cursor:"pointer",
                                 fill: active ? C.crimson : "#EAF0EC",
                                 stroke: active ? C.gold : C.navy,
                                 strokeWidth: active ? 1.4 : 0.5,
                                 transition:"fill .12s" }}
                        onMouseEnter={(e)=>{ if(!active) e.target.style.fill = "#D9E6DC"; }}
                        onMouseLeave={(e)=>{ if(!active) e.target.style.fill = "#EAF0EC"; }}>
                        <title>{f.properties.name}</title>
                      </path>
                    );
                  })}
                </g>
              </svg>}
          <div style={{ fontSize:11, color:C.muted, marginTop:4 }}>
            Geometry: U.S. Census cartographic boundaries (simplified for display).
          </div>
        </div>

        {/* COUNTY LIST */}
        <div style={{ flex:"1 1 240px", minWidth:220, maxWidth:300 }}>
          <PanelTitle>Counties{selState ? ` · ${counties.length}` : ""}</PanelTitle>
          {!selState
            ? <Empty>Click a state to list its counties.</Empty>
            : <>
                <input value={countyFilter} onChange={e=>setCountyFilter(e.target.value)}
                  placeholder="Filter counties…"
                  style={inputStyle} />
                <ScrollList>
                  {filtered.map(c => (
                    <ListItem key={c.fips} active={selCounty?.fips===c.fips}
                      onClick={()=>selectCounty(c)}>{c.name}</ListItem>
                  ))}
                </ScrollList>
              </>}
        </div>

        {/* CITY LIST */}
        <div style={{ flex:"1 1 200px", minWidth:200, maxWidth:280 }}>
          <PanelTitle>Cities{cities ? ` · ${cities.length}` : ""}</PanelTitle>
          {!selCounty
            ? <Empty>Select a county to list its cities.</Empty>
            : citiesLoading
              ? <Empty>Loading cities…</Empty>
              : (cities && cities.length)
                ? <ScrollList>
                    {cities.map(name => (
                      <ListItem key={name} onClick={()=>onCitySelect && onCitySelect({ name, county:selCounty, state:selState })}>
                        {name}
                      </ListItem>
                    ))}
                  </ScrollList>
                : <Empty>No incorporated cities are listed for this county.</Empty>}
        </div>
      </div>
    </div>
  );
}

// --- small styled helpers ---
const inputStyle = { width:"100%", boxSizing:"border-box", padding:"7px 10px", marginBottom:8,
  fontFamily:serif, fontSize:13, border:`1px solid ${C.line}`, borderRadius:4, background:"#fff" };
const PanelTitle = ({children}) => (
  <div style={{ fontSize:12, fontWeight:700, color:C.navy, letterSpacing:1,
                borderBottom:`2px solid ${C.gold}`, paddingBottom:5, marginBottom:8 }}>{children}</div>
);
const Empty = ({children}) => (
  <div style={{ fontSize:12.5, color:C.muted, fontStyle:"italic", padding:"6px 2px" }}>{children}</div>
);
const ScrollList = ({children}) => (
  <div style={{ maxHeight:300, overflowY:"auto", border:`1px solid ${C.line}`, borderRadius:4, background:"#fff" }}>{children}</div>
);
const ListItem = ({active, onClick, children}) => (
  <div onClick={onClick} className="cyr-map-list-item" style={{ padding:"7px 11px", fontSize:13.5, cursor:"pointer",
       background: active ? C.crimson : "transparent", color: active ? "#fff" : C.ink,
       borderBottom:`1px solid ${C.parchmentEdge}` }}
    onMouseEnter={e=>{ if(!active) e.currentTarget.style.background = C.parchmentEdge; }}
    onMouseLeave={e=>{ if(!active) e.currentTarget.style.background = "transparent"; }}>
    {children}
  </div>
);
const StarStrip = () => (
  <div style={{ background:C.navy, padding:"6px 0", display:"flex", justifyContent:"center", gap:9 }}>
    {Array.from({length:13}).map((_,i)=><span key={i} style={{color:C.gold, fontSize:11}}>★</span>)}
  </div>
);

